contracts/Lock.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract Lock {
    uint256 public unlockTime;
    address payable public owner;

    event Withdrawal(uint256 amount, uint256 when);

    constructor(uint256 _unlockTime) payable {
        require(block.timestamp < _unlockTime, "Unlock time should be in the future");
        unlockTime = _unlockTime;
        owner = payable(msg.sender);
    }

    function withdraw() public {
        require(block.timestamp >= unlockTime, "You can't withdraw yet");
        require(msg.sender == owner, "You aren't the owner");

        emit Withdrawal(address(this).balance, block.timestamp);
        owner.transfer(address(this).balance);
    }
}

contracts/MyToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract MyToken is ERC20, Ownable {
    mapping(bytes32 => bool) public activeHashes;
    bytes32[] public allImageHashes;
    mapping(bytes32 => bool) public deletedHashes;

    event ImageHashUploaded(address indexed uploader, bytes32 hash);
    event ImageHashDeleted(address indexed uploader, bytes32 hash);
    event ImageHashRestored(address indexed restorer, bytes32 hash, bool isActive);

    constructor() ERC20("MyToken", "MTK") Ownable(msg.sender) {}

    function uploadImageHash(bytes32 hash) public {
        require(!activeHashes[hash], "Hash already exists");
        activeHashes[hash] = true;
        allImageHashes.push(hash);
        deletedHashes[hash] = false;
        emit ImageHashUploaded(msg.sender, hash);
    }

    function isImageHashActive(bytes32 hash) public view returns (bool) {
        return activeHashes[hash] && !deletedHashes[hash];
    }

    function deleteImageHash(bytes32 hash) public onlyOwner {
        require(activeHashes[hash], "Hash does not exist");
        require(!deletedHashes[hash], "Hash is already deleted");
        deletedHashes[hash] = true;
        emit ImageHashDeleted(msg.sender, hash);
    }

    function getHashCount() external view returns (uint256) {
        return allImageHashes.length;
    }

    function restoreHash(bytes32 hash, bool isActive) public onlyOwner {
        if (!activeHashes[hash] && !deletedHashes[hash]) {
            allImageHashes.push(hash);
        }
        activeHashes[hash] = isActive;
        deletedHashes[hash] = !isActive;
        emit ImageHashRestored(msg.sender, hash, isActive);
    }
    
    function batchRestoreHashes(
        bytes32[] calldata hashes, 
        bool[] calldata activeStatuses
    ) external onlyOwner {
        require(hashes.length == activeStatuses.length, "Array length mismatch");
        
        for (uint i = 0; i < hashes.length; i++) {
            // 直接调用内部函数
            restoreHash(hashes[i], activeStatuses[i]);
        }
    }
    
    function getAllImageHashes() external view returns (bytes32[] memory) {
        // 直接返回所有哈希数组，不再过滤活跃状态
        return allImageHashes;
    }

    // 添加新函数获取活跃哈希数量
    function getActiveHashCount() external view returns (uint256) {
        uint256 activeCount = 0;
        for (uint i = 0; i < allImageHashes.length; i++) {
            if (isImageHashActive(allImageHashes[i])) {
                activeCount++;
            }
        }
        return activeCount;
    }
}

